INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(6, 6, 7, 'Pastel Salón', 'Único y original pastel de chocolate embebido con jarabe marrasquino, relleno de crema de chocolate y avellanas, decorado de exquisitos rizos de chocolate de leche elaborados artesanalmente.', 709, 100, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(7, 6, 7, 'Pastel Mil Hojas', 'Clásico pastel de El Globo, elaborado con dos capas de suave crema láctea y tres galletas feite horneadas. Decorado con nuestros tradicionales y crujientes aros espolvoreados de azúcar glass.', 699, 40, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(8, 6, 7, 'Pastel Durazno', 'Delicioso pastel de vainilla con un toque de nuestra receta de tres leches con un toque de rompope, relleno con una exquisita crema y duraznos. Decorado con una compota de duraznos y almendra.', 699, 30, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(9, 7, 10, 'Rosca de Naranja', 'Esponjoso pan infusionado con naranja y bañado en mantequilla y miel de naranja para un sabor inolvidable.', 299, 30, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(10, 5, 10, 'Rosca Brioche', '¡Prepárate para disfrutar del pan más esponjoso!\r\n\r\nNuestra deliciosa Rosca Brioche es un exquisito pan de levadura, relleno de queso crema y cobertura de glaseado especial de la casa.\r\n\r\n*El glaseado viene aparte', 475, 50, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(11, 5, 11, 'Bolitas de Queso', '¡El clásico de clásicos! Nuestras deliciosas Bolitas de Queso: Crujientes bolitas escarchadas con azúcar, elaboradas con pasta tipo hojaldre y rellenas de queso crema.\r\n\r\nIncluye 12 piezas.', 315, 60, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(12, 5, 11, 'Hojaldritas', '¿Estás listo para probar la especialidad de la casa? Nuestras Hojaldritas son láminas de crujiente hojaldre, rellenas de jamón y queso, escarchados con azúcar ligeramente caramelizada.\r\n\r\nIncluye 8 piezas.', 330, 60, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(13, 5, 11, 'Brownies', 'Disfruta de nuestros únicos Brownies, deliciosos panecitos de chocolate, elaborados con la receta especial de la casa y decorados con azúcar glass.\r\n*Para mantener la frescura del producto el azúcar glass se envía por aparte.\r\n\r\nIncluye 8 piezas.', 305, 90, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(14, 6, 8, 'Chocolatín', 'Pan hojaldrado, crujiente, relleno de chocolate oscuro de Bélgica.', 36, 100, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(15, 6, 8, 'Concha Chocolate', 'Pan de miga suave y esponjosa, elaborado con mantequilla y galleta de chocolate.', 30, 80, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(16, 6, 8, 'Croissant', 'Pan hojaldrado elaborado 100% con mantequilla de Bélgica.', 36, 70, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(17, 7, 10, 'Rosca de Churro', '¡La rosca para acompañar tus tardes! Esponjoso pan inspirado en los sabores del churro,  cubierta de canela, especias y azúcar que hacen el equilibrio perfecto de dulzura y calidez.', 235, 60, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(18, 6, 7, 'Pastel 3 Leches de Chocolate', 'Clásico pastel elaborado con un esponjoso bizcocho de chocolate, bañado con 3 Leches de chocolate y brandy, combinando con una crema de truffa. Hecho con La Lechera®', 599, 20, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(19, 6, 7, 'Pastel 4 Chocolates', 'Pastel elaborado con delicioso pan de chocolate tipo brownie relleno con mousse de chocolate blanco, chocolate de leche, chocolate amargo cubierto con glasé de chocolate blanco.', 599, 10, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(20, 7, 7, 'Pastel Dulce de Leche', '¡Un Pastel de Tres Leches reinventado!\r\nPan de vainilla bañado en nuestra mezcla secreta de tres leches y relleno con crema pastelera y cubierto con una suave crema de dulce de leche lo que le da un sabor suave y delicado que te encantará.', 445, 28, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(21, 7, 11, 'Macarrón Dubai', 'Descubre el nuevo Macarrón Dubai de chocolate con pistache, una combinación irresistible que eleva cualquier antojo. Este delicado macarrón está elaborado con base de chocolate, relleno de una suave crema de pistache y un delicioso spread de chocolate, decorado con trozos de pistache para un toque final perfecto.\r\n\r\nIdeal para quienes buscan postres gourmet, sabores intensos y una experiencia diferente en cada bocado. Perfecto para acompañar tu café o como un detalle especial.', 152, 58, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(22, 7, 10, 'Rosca Decorada', '¿Te gusta el brownie de Marisa? Entonces la Rosca decorada se convertirá en tu favorita:\r\npan de brownie con chocolate y nuez, cubierto con choco', 420, 20, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(23, 7, 9, 'Galleta Onza', '¿Te gusta el brownie de Marisa? Entonces la Rosca decorada se convertirá en tu favorita:\r\npan de brownie con chocolate y nuez, cubierto con choco', 115, 40, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(24, 7, 9, 'Galleta Nenas', 'Las galletas más famosas de México.\r\n\r\nNuestra crujiente Galleta Espejo, hecha de mantequilla y cubierta en azúcar la rellenamos con dulce de leche para hacer una galleta de la que todo mundo se enamora.\r\n\r\n\r\nTIP: Acompañan perfecto con tu café, pero si quieres llevarlas al siguiente nivel pásalas al asador en tu siguiente reunión y será el postre más exitoso del día.', 325, 90, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(25, 7, 9, 'Galleta Francesa', 'Una delicia para paladares exigentes: La Galleta Francesa está hecha con auténtica mantequilla francesa de la más alta calidad para lograr una galleta que casi se derrite en tu boca, con trocitos de azúcar para un bocado inolvidable.', 120, 119, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(26, 6, 8, 'Mini Garibaldi', 'El único y original panqué de vainilla bañado con pulpa 100% de chabacano, cubierto con gragea blanca.', 14, 40, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(27, 6, 10, 'Rosca Garibaldi', 'Rosca elaborada a base de panqué de vainilla bañado con pulpa 100% de chabacano, cubierto con gragea blanca.', 219, 90, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(28, 7, 9, 'Galleta Doradita', 'Una galleta delgadita ¡pero súper crujiente! La llenamos de almendra tostada que endulzamos ligeramente para lograr un sabor que no vas a olvidar.', 115, 56, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(29, 7, 9, 'Galleta Centenario', '¡La que nos puso en el mapa! Suave galleta de mantequilla rellena de mermelada casera de fresa o chabacano y espolvoreadas con azúcar glass.\r\n\r\nSu delicioso sabor casero es lo que las ha hecho las favoritas por más de 30 años.', 110, 78, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(30, 7, 9, 'Galleta de Almendra', 'Deliciosa y crujiente galleta de naranja con almendra fileteada. Perfecta para compartir con amigos.', 110, 56, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(31, 6, 8, 'Trenza Chocolate y Nuez', 'Pan elaborado con pasta de croissant con chispas de chocolate y trozos de nuez.', 39, 41, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(32, 6, 8, 'Baguette con Ajonjolí', 'Baguette artesanal con ajonjolí con corteza gruesa y crujiente, decorado de ajonjolí blanco y con notas ácidas provenientes de masa madre de centeno.', 29, 63, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(33, 6, 11, 'Muffin Chocolate', 'Muffin de chocolate con chispas de chocolate.', 39, 45, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
(34, 7, 11, 'Muffin de Chocolate', '¡Tu pastel favorito, hecho muffin!\r\nEste delicioso muffin está hecho con nuestro famoso pan de chocolate, betún y chispas de chocolate.\r\n\r\nUna delicia perfecta para un gustito personal.', 30, 54, );
INSERT INTO `products` (`id`, `supplier_id`, `category_id`, `name`, `description`, `price`, `stock`, `image`) VALUES
